/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trisolv(int n,
                    std::vector<std::vector<double>>& L,
                    std::vector<double>& x,
                    std::vector<double>& b)
{
    /* Perform a forward substitution against a lower‑triangular
       matrix L (n×n).  The computation is inherently sequential
       because each row depends on all previous rows, so it
       cannot be paralellised.  The code below only exploits
       auto‑vectorisation of the inner loop.
    */
#pragma clang loop vectorize(enable)
    for (int i = 0; i < n; ++i) {
        double sum = b[i];
        const std::vector<double> &Li = L[i];

#pragma clang loop vectorize(enable)
        for (int j = 0; j < i; ++j)
            sum -= Li[j] * x[j];

        x[i] = sum / Li[i];
    }
}
