void kernel_gemm(int ni, int nj, int nk,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B,
                 std::vector<std::vector<double>>& C)
{
    // Parallelise over the outermost loop (rows of C).
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i)
    {
        double* c_row = C[i].data();        // pointer to the start of row i in C
        const double* a_row = A[i].data();  // pointer to the start of row i in A

        // C[i][j] *= beta
        for (int j = 0; j < nj; ++j)
            c_row[j] *= beta;

        // Main loop: C[i][j] += alpha * A[i][k] * B[k][j]
        for (int k = 0; k < nk; ++k)
        {
            double aik = alpha * a_row[k];
            const double* b_row = B[k].data();  // pointer to the start of row k in B
            for (int j = 0; j < nj; ++j)
                c_row[j] += aik * b_row[j];
        }
    }
}
