void kernel_covariance(int m, int n,
                       std::vector<std::vector<double>>& data,
                       std::vector<std::vector<double>>& cov,
                       std::vector<double>& mean)
{
    /* -------------------- 1. Compute mean -------------------- */
    /* Parallel reduction for each column */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) sum += data[i][j];
        mean[j] = sum / n;
    }

    /* -------------------- 2. Center the data -------------------- */
    /* Broadcast the mean to every element of the matrix */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < m; ++j)
            data[i][j] -= mean[j];

    /* -------------------- 3. Compute covariance -------------------- */
    /* We compute only the upper triangle and mirror it later */
    #pragma omp parallel for collapse(2) schedule(guided)
    for (int i = 0; i < m; ++i) {
        for (int j = i; j < m; ++j) {
            double s = 0.0;
            for (int k = 0; k < n; ++k)
                s += data[k][i] * data[k][j];
            cov[i][j] = s / (n - 1.0);
            cov[j][i] = cov[i][j];   // fill symmetric entry
        }
    }
}
