#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_symm(int m, int n,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B)
{
    /* The algorithm follows:
       C := alpha*A*B + beta*C
       A is MxM, B is MxN, C is MxN.
       For each row i the algorithm uses the lower triangular part
       of A (in the sense of BLAS upper–triangular storage). */

    /* Use OpenMP to parallelise the outer two loops.
       The inner loop over k is small enough that keeping it
       sequential gives the best locality. */
#pragma omp parallel for schedule(static) collapse(2)
    for (int i = 0; i < m; ++i)
    {
        /* Load diagonal element once – it is reused for all j. */
        const double aii = A[i][i];
        for (int j = 0; j < n; ++j)
        {
            double sum = 0.0;
            const double bij = B[i][j];
            /* Accumulate the contribution from the lower part of A. */
            for (int k = 0; k < i; ++k)
            {
                const double aik = A[i][k];
                C[k][j] += alpha * bij * aik;
                sum    += B[k][j] * aik;
            }
            /* Complete the update of C[i][j]. */
            C[i][j] = beta * C[i][j] + alpha * bij * aii + alpha * sum;
        }
    }
}
