void kernel_jacobi_1d(int tsteps,
                      int n,
                      std::vector<double>& A,
                      std::vector<double>& B) {
    // Raw pointers for faster access
    double* a = A.data();
    double* b = B.data();

    // Constant factor
    constexpr double coef = 0.33333;

    for (int t = 0; t < tsteps; ++t) {
        // Update B from A
        #pragma omp parallel for schedule(static, 4096)
        for (int i = 1; i < n - 1; ++i) {
            b[i] = coef * (a[i - 1] + a[i] + a[i + 1]);
        }

        // Update A from B
        #pragma omp parallel for schedule(static, 4096)
        for (int i = 1; i < n - 1; ++i) {
            a[i] = coef * (b[i - 1] + b[i] + b[i + 1]);
        }
    }
}
