void kernel_seidel_2d(int tsteps, int n, std::vector<std::vector<double>>& A)
{
    /* Flatten the 2‑D vector into a 1‑D array for contiguous access. */
    double* const data = &A[0][0];
    const int stride = n;                    // number of columns
    const double inv9 = 1.0 / 9.0;

#pragma omp parallel for schedule(static)
    for (int t = 0; t < tsteps; ++t) {
        /* The non‑border cells form an inner n-2 × n-2 block. */
        for (int i = 1; i <= n - 2; ++i) {
            const long base = static_cast<long>(i) * stride;          // offset of row i
            const long bu = base + 1;                                // start of inner j
            const long buf = base + stride;                          // row i+1
            const long bef = base - stride;                          // row i-1

            /* Use local pointer for the inner row to avoid repeated
               array indexing. The loop stays cache‑friendly because
               bu, bef, buf are contiguous. */
            for (int j = 1; j <= n - 2; ++j) {
                const long idx = bu + j;            // i,j
                data[idx] = (
                    data[bef + j - 1] + data[bef + j] + data[bef + j + 1] +
                    data[bef + j] +                                   // i-1 row
                    data[idx - 1] + data[idx] + data[idx + 1] +         // current row
                    data[buf + j - 1] + data[buf + j] + data[buf + j + 1]
                ) * inv9;
            }
        }
    }
}
