void kernel_jacobi_2d(int tsteps,
		      int n,
		      std::vector<std::vector<double>>& A,
		      std::vector<std::vector<double>>& B) {
    // obtain raw pointers to the underlying contiguous memory
    double* a = &A[0][0];
    double* b = &B[0][0];
    const std::size_t stride = static_cast<std::size_t>(n);

    const double coeff = 0.2;
    for (int t = 0; t < tsteps; ++t) {
        /* B = 0.2 * (A + 4 neighbors) */
#pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i < n-1; ++i) {
            for (int j = 1; j < n-1; ++j) {
                std::size_t idx = static_cast<std::size_t>(i*n + j);
                b[idx] = coeff * (a[idx]
                                 + a[idx-1]          // left
                                 + a[idx+1]          // right
                                 + a[idx+stride]     // down
                                 + a[idx-stride]    // up
                                 );
            }
        }

        /* A = 0.2 * (B + 4 neighbors) */
#pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i < n-1; ++i) {
            for (int j = 1; j < n-1; ++j) {
                std::size_t idx = static_cast<std::size_t>(i*n + j);
                a[idx] = coeff * (b[idx]
                                 + b[idx-1]
                                 + b[idx+1]
                                 + b[idx+stride]
                                 + b[idx-stride]
                                 );
            }
        }
    }
