/* Helper to obtain a raw pointer to the underlying contiguous
   storage of a std::vector<std::vector<double>> that is known
   to be a proper n×n array. */
static inline double* raw_matrix(std::vector<std::vector<double>>& M)
{
    return &M[0][0];
}

/* Optimized kernel avoiding bounds checks, with cache‑friendly
   blocking and a parallel outer loop.  The interface remains
   identical to the original harness. */
void kernel_gesummv(int n,
		    double alpha,
		    double beta,
		    std::vector<std::vector<double>>& A,
		    std::vector<std::vector<double>>& B,
		    std::vector<double>& tmp,
		    std::vector<double>& x,
		    std::vector<double>& y)
{
    const std::size_t block = 64;            // block size tuned for L1 cache
    double *a = raw_matrix(A);
    double *b = raw_matrix(B);
    double *xptr = x.data();
    double *yptr = y.data();
    double *tmpPtr = tmp.data();

    /* Parallelize the outermost loop over rows; each thread
       works on a distinct set of rows. */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double *aRow = a + i * n;
        double *bRow = b + i * n;
        double sumT = 0.0;
        double sumY = 0.0;

        /* Blocked inner loop for better temporal locality */
        for (int jj = 0; jj < n; jj += block) {
            int jlim = (jj + block < n) ? jj + block : n;
            for (int j = jj; j < jlim; ++j) {
                double xj = xptr[j];
                sumT += aRow[j] * xj;
                sumY += bRow[j] * xj;
            }
        }

        tmpPtr[i] = sumT;
        yptr[i]  = alpha * sumT + beta * sumY;
    }
}
