/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_cholesky(int n,
		     std::vector<std::vector<double>>& A) {
    // Use raw pointers for speed: each row already has contiguous storage.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* const row_i = A[i].data();

        /* Upper part of the i‑th row (j < i). */
        for (int j = 0; j < i; ++j) {
            double* const row_j = A[j].data();
            double sum = 0.0;
            for (int k = 0; k < j; ++k) {
                sum += row_i[k] * row_j[k];
            }
            row_i[j] = (row_i[j] - sum) / row_j[j];
        }

        /* Diagonal element. */
        double sum = 0.0;
        for (int k = 0; k < i; ++k) {
            sum += row_i[k] * row_i[k];
        }
        row_i[i] = std::sqrt(row_i[i] - sum);
    }
}
