void kernel_floyd_warshall(int n, std::vector<std::vector<int>>& path) {
    // Use a slightly more cache‑friendly approach for the innermost loop.
    // Each iteration of the inner j loop is independent; we can parallelise
    // the i‑loop with OpenMP.  The whole algorithm remains numerically
    // identical to the reference O(n³) Floyd–Warshall.
    for (int k = 0; k < n; ++k) {
        // Grab a pointer to the k‑th row once outside the i loop to avoid
        // repeated indexing through the outer vector.
        const std::vector<int>* k_row = &path[k];

        #pragma omp parallel for schedule(static)
        for (int i = 0; i < n; ++i) {
            std::vector<int> *i_row = &path[i];
            // Grab a pointer to the i‑th row inside the critical section
            // of the parallel region so the compiler can keep it in a register.
            std::vector<int> *i_vec = &path[i];
            // The innermost loop can be manually unrolled for a modest gain.
            for (int j = 0; j < n; ++j) {
                int via_k = (*i_vec)[k] + (*k_row)[j];
                if (via_k < (*i_vec)[j]) (*i_vec)[j] = via_k;
            }
        }
    }
}
