// Optimised implementation of the Jacobi-SYRK kernel.
// The behaviour is identical to the reference version,
// but the inner loops are cache‑friendly, vectorised
// and parallelised with OpenMP.

#include <vector>
#include <omp.h>
#include <cstring>

extern "C" void kernel_syrk(int n, int m,
                            double alpha,
                            double beta,
                            std::vector<std::vector<double>>& C,
                            std::vector<std::vector<double>>& A)
{
    // Flatten the 2‑D vectors for faster indexing
    const double *Adata = &A[0][0];          // A is n × m
    double *Cdata = &C[0][0];                // C is n × n

    const int strideA = m;   // number of columns in A
    const int strideC = n;   // number of columns in C

    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double *Crow = Cdata + i * strideC;          // start of row i in C
        const double *Arow = Adata + i * strideA;    // start of row i in A

        // Scale lower-triangular part of C[i][j] by beta
        for (int j = 0; j <= i; ++j) {
            Crow[j] *= beta;
        }

        // Accumulate alpha * A[i][k] * A[j][k] for all k
        for (int k = 0; k < m; ++k) {
            double aik = Arow[k];                                   // A[i][k]
            double alpha_aik = alpha * aik;                         // α*A[i][k]
            const double *Akcol = Adata + k * strideA;              // A[*,k]
            // Update C[i][j] for j <= i
            for (int j = 0; j <= i; ++j) {
                Crow[j] += alpha_aik * Akcol[j];                    // C[i][j] += α*A[i][k]*A[j][k]
            }
        }
    }
}
