/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_doitgen(int nr, int nq, int np,
		    std::vector<std::vector<std::vector<double>>>& A,
		    std::vector<std::vector<double>>& C4,
		    std::vector<double>& sum) {
    // Allocate a temporary buffer once; reuse it for all (r,q) pairs.
    std::vector<double> local(np);

    // Reduce overhead by collapsing the two outer loops (r and q) into a single
    // parallel work‑sharing loop.  The inner p‑loop is intentionally left
    // serial to ease register usage and maintain the deterministic order.
    #pragma omp parallel for collapse(2) schedule(static)
    for (int r = 0; r < nr; ++r) {
        for (int q = 0; q < nq; ++q) {
            // Compute the matrix product A[r][q][s] * C4[s][p] for all p.
            // We reuse the same 'local' buffer for each (r,q) iteration.
            for (int p = 0; p < np; ++p) {
                double acc = 0.0;
                for (int s = 0; s < np; ++s) {
                    acc += A[r][q][s] * C4[s][p];
                }
                local[p] = acc;
            }

            // Copy the result back to A[r][q][p].
            for (int p = 0; p < np; ++p) {
                A[r][q][p] = local[p];
            }
        }
    }
}
