/*
 * Optimized Nussinov kernel.
 * Uses a diagonal (length‑based) loop ordering and OpenMP parallelism.
 * The algorithmic behaviour is identical to the reference implementation.
 */

static inline int match_bases(int b1, int b2) noexcept {
    return (b1 + b2 == 3) ? 1 : 0;   // 0↔3 and 1↔2 are complementary
}

void kernel_nussinov(int n, std::vector<int>& seq,
                     std::vector<std::vector<int>>& table)
{
    // The table is already N×N with standard row‑major layout.
    // We use direct indexing to avoid overhead of vector-of‑vectors access.
#pragma omp parallel for schedule(static)
    for (int len = 2; len <= n; ++len) {          // subsequence length
        // For each fixed length, all (i, j) are independent and can be processed in parallel
        for (int i = 0; i <= n - len; ++i) {
            int j = i + len - 1;

            int best = table[i][j];             // current cell (initially 0)

            // Propagate from left/right neighbours
            if (j - 1 >= 0)
                best = std::max(best, table[i][j - 1]);
            if (i + 1 < n)
                best = std::max(best, table[i + 1][j]);

            // Pair i and j (or skip one if they are adjacent)
            if (i < j - 1)
                best = std::max(best, table[i + 1][j - 1] + match_bases(seq[i], seq[j]));
            else
                best = std::max(best, table[i + 1][j - 1]);

            // Split the interval at every possible k
            int t = best;
            for (int k = i + 1; k < j; ++k) {
                int val = table[i][k] + table[k + 1][j];
                if (val > t) t = val;
            }
            table[i][j] = t;
        }
    }
}
