/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_atax(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& x,
                 std::vector<double>& y,
                 std::vector<double>& tmp) {

    /* Clear y in parallel */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) y[i] = 0.0;

    /* Main computation: O(m*n) linear algebra */
    #pragma omp parallel
    {
        /* Each thread keeps a private y vector to avoid atomic updates */
        std::vector<double> y_local(n, 0.0);

        #pragma omp for schedule(static)
        for (int i = 0; i < m; ++i) {
            double dot = 0.0;
            for (int j = 0; j < n; ++j) {
                dot += A[i][j] * x[j];
            }
            tmp[i] = dot;
            for (int j = 0; j < n; ++j) {
                y_local[j] += A[i][j] * dot;
            }
        }

        /* Combine per‑thread y into the final vector */
        #pragma omp critical
        for (int j = 0; j < n; ++j) {
            y[j] += y_local[j];
        }
    }
}
