void kernel_lu(int n, std::vector<std::vector<double>>& A) {
    for (int i = 0; i < n; ++i) {
        double* const Ai = A[i].data();          // row i pointer

        // --- first part: j < i -------------------------------------------------
        for (int j = 0; j < i; ++j) {
            double sum = 0.0;
            // accumulate A[i][k] * A[k][j] for k < j
            for (int k = 0; k < j; ++k) {
