void kernel_correlation(int m, int n,
			std::vector<std::vector<double>>& data,
			std::vector<std::vector<double>>& corr,
			std::vector<double>& mean,
			std::vector<double>& stddev) {
    constexpr double eps = 0.1;
    constexpr double inv_sqrt_n = 1.0 / std::sqrt(static_cast<double>(n));

    /* ----------------------------------------------------------
       1. Compute means (per column)
       ---------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) {
            sum += data[i][j];
        }
        mean[j] = sum / n;
    }

    /* ----------------------------------------------------------
       2. Compute standard deviations (per column)
       ---------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double sum_sq = 0.0;
        for (int i = 0; i < n; ++i) {
            double diff = data[i][j] - mean[j];
            sum_sq += diff * diff;
        }
        double var = sum_sq / n;
        double sd = std::sqrt(var);
        stddev[j] = (sd <= eps) ? 1.0 : sd;
    }

    /* ----------------------------------------------------------
       3. Normalize data in-place: subtract mean, divide by
          sqrt(n)*stddev
       ---------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            data[i][j] = (data[i][j] - mean[j]) * inv_sqrt_n / stddev[j];
        }
    }

    /* ----------------------------------------------------------
       4. Compute correlation matrix
          corr[i][j] = sum_k data[k][i]*data[k][j]
          (symmetry exploited)
       ---------------------------------------------------------- */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < m - 1; ++i) {
        corr[i][i] = 1.0;
        for (int j = i + 1; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k) {
                sum += data[k][i] * data[k][j];
            }
            corr[i][j] = sum;
            corr[j][i] = sum;
        }
    }
    corr[m-1][m-1] = 1.0;
}
