/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_durbin(int n,
                   std::vector<double>& r,
                   std::vector<double>& y) {

    // Allocate once and reuse across calls to avoid per-call allocations.
    static thread_local std::vector<double> z;
    if ((int)z.size() != n) z.resize(n);

    // Set initial values.
    y[0]   = -r[0];
    double beta  = 1.0;
    double alpha = -r[0];

    for (int k = 1; k < n; ++k) {
        // Update beta.
        beta *= 1.0 - alpha * alpha;

        // Compute the correlation sum.
        double sum = 0.0;
        const double* rptr = r.data() + k - 1;
        const double* yptr = y.data();
        for (int i = 0; i < k; ++i) {
            sum += *rptr-- * yptr[i];
        }

        // New reflection coefficient.
        alpha = -(r[k] + sum) / beta;

        // Compute new y using a temporary buffer z.
        double* zptr = z.data();
        for (int i = 0; i < k; ++i) {
            zptr[i] = yptr[i] + alpha * yptr[k - i - 1];
        }
        // Copy back to y.
        std::memcpy(yptr, zptr, k * sizeof(double));

        y[k] = alpha;
    }
}
