    double* Ex = &ex[0][0];
    double* Ey = &ey[0][0];
    double* Hz = &hz[0][0];

    const int stride = ny;   // distance between consecutive columns in inner dimension

    for (int t = 0; t < tmax; ++t) {
        /* 1. Update boundary cells of ey */
        #pragma omp parallel for
        for (int j = 0; j < ny; ++j)
            Ey[j] = _fict_[t];

        /* 2. update ey for i > 0 */
        #pragma omp parallel for collapse(2)
        for (int i = 1; i < nx; ++i) {
            int base = i * stride;
            int prev = (i-1) * stride;
            for (int j = 0; j < ny; ++j)
                Ey[base + j] -= c1 * (Hz[base + j] - Hz[prev + j]);
        }

        /* 3. update ex for j > 0 */
        #pragma omp parallel for collapse(2)
        for (int i = 0; i < nx; ++i) {
            int base = i * stride;
            for (int j = 1; j < ny; ++j)
                Ex[base + j] -= c1 * (Hz[base + j] - Hz[base + j - 1]);
