/* Main computational kernel.  The whole function will be timed,
   including the call and return.  This implementation keeps the
   same public signature but works on a flat, contiguous memory
   layout for maximum performance. */

/* QR Decomposition with Modified Gram Schmidt:
   http://www.inf.ethz.ch/personal/gander/ */
void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q) {
    /* Flatten the input matrix A into a contiguous array.
       A may be non‑contiguous (vector of vectors), so we copy it locally.
       The same holds for Q and R. */
    std::vector<double> Aflat(m * n);
    std::vector<double> Qflat(m * n, 0.0);
    std::vector<double> Rflat(n * n, 0.0);

    // Copy A into Aflat in column‑major order
    for (int j = 0; j < n; ++j) {
        for (int i = 0; i < m; ++i) {
            Aflat[j * m + i] = A[i][j];
        }
    }

    /* Main Modified Gram–Schmidt loop */
    for (int k = 0; k < n; ++k) {
        /* Compute the norm of column k of A (now in Aflat) */
        double nrm_sq = 0.0;
        #pragma omp simd reduction(+:nrm_sq)
        for (int i = 0; i < m; ++i) {
            double v = Aflat[k * m + i];
            nrm_sq += v * v;
        }
        double norm = std::sqrt(nrm_sq);
        Rflat[k * n + k] = norm;

        /* Compute column k of Q (normalize) */
        #pragma omp parallel for
        for (int i = 0; i < m; ++i) {
            Qflat[k * m + i] = Aflat[k * m + i] / norm;
        }

        /* Orthogonalize remaining columns */
        for (int j = k + 1; j < n; ++j) {
            double rkj = 0.0;

            /* rkj = Q_k^T * A_j */
            #pragma omp simd
            for (int i = 0; i < m; ++i) {
                rkj += Qflat[k * m + i] * Aflat[j * m + i];
            }
            Rflat[k * n + j] = rkj;

            /* A_j = A_j - Q_k * rkj */
            #pragma omp parallel for
            for (int i = 0; i < m; ++i) {
                Aflat[j * m + i] -= Qflat[k * m + i] * rkj;
            }
        }
    }

    /* Copy results back into the original 2‑D structures */
    for (int j = 0; j < n; ++j) {
        for (int i = 0; i < m; ++i) {
            Q[i][j] = Qflat[j * m + i];
            if (i <= j)   // upper–triangular part of R
                R[i][j] = Rflat[i * n + j];
            else
                R[i][j] = 0.0;
        }
    }
}
