/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_3mm(int ni, int nj, int nk, int nl, int nm,
                std::vector<std::vector<double>>& E,
                std::vector<std::vector<double>>& A,
                std::vector<std::vector<double>>& B,
                std::vector<std::vector<double>>& F,
                std::vector<std::vector<double>>& C,
                std::vector<std::vector<double>>& D,
                std::vector<std::vector<double>>& G) {

    /* Flatten matrices into contiguous arrays for faster access */
    double* dE = new double[ni * nj];
    double* dA = flatten(A, ni, nk);
    double* dB = flatten(B, nk, nj);
    double* dF = new double[nj * nl];
    double* dC = flatten(C, nj, nm);
    double* dD = flatten(D, nm, nl);
    double* dG = new double[ni * nl];

    /* Compute E = A * B */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < ni; ++i) {
        for (int j = 0; j < nj; ++j) {
            double sum = 0.0;
            const double* arow = dA + i * nk;
            const double* brow = dB + j;
            for (int k = 0; k < nk; ++k, brow += nj)
                sum += arow[k] * brow[0];
            dE[i * nj + j] = sum;
        }
    }

    /* Compute F = C * D */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < nj; ++i) {
        for (int j = 0; j < nl; ++j) {
            double sum = 0.0;
            const double* crow = dC + i * nm;
            const double* drow = dD + j;
            for (int k = 0; k < nm; ++k, drow += nl)
                sum += crow[k] * drow[0];
            dF[i * nl + j] = sum;
        }
    }

    /* Compute G = E * F */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < ni; ++i) {
        for (int j = 0; j < nl; ++j) {
            double sum = 0.0;
            const double* erow = dE + i * nj;
            const double* fcol = dF + j;
            for (int k = 0; k < nj; ++k, fcol += nl)
                sum += erow[k] * fcol[0];
            dG[i * nl + j] = sum;
        }
    }

    /* Copy results back into the output vectors */
    unflatten(dE, E, ni, nj);
    unflatten(dF, F, nj, nl);
    unflatten(dG, G, ni, nl);

    /* Clean up */
    delete[] dE; delete[] dF; delete[] dG;
    delete[] dA; delete[] dB; delete[] dC; delete[] dD;
