/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_ludcmp(int n,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& b,
                   std::vector<double>& x,
                   std::vector<double>& y) {

    // ============================
    // 1. LU decomposition
    // ============================
    for (int i = 0; i < n; ++i) {
        // ---- L part ------------------------------------
        for (int j = 0; j < i; ++j) {
            double w = A[i][j];
            // compute dot product of row i and column j
            for (int k = 0; k < j; ++k) {
                w -= A[i][k] * A[k][j];
            }
            A[i][j] = w / A[j][j];
        }

        // ---- U part ------------------------------------
        for (int j = i; j < n; ++j) {
            double w = A[i][j];
            for (int k = 0; k < i; ++k) {
                w -= A[i][k] * A[k][j];
            }
            A[i][j] = w;
        }
    }

    // ============================
    // 2. Forward substitution Ly = b
    // ============================
    for (int i = 0; i < n; ++i) {
        double w = b[i];
        // sum A[i][j] * y[j] for j < i
        for (int j = 0; j < i; ++j) {
            w -= A[i][j] * y[j];
        }
        y[i] = w;
    }

    // ============================
    // 3. Backward substitution Ux = y
    // ============================
    for (int i = n - 1; i >= 0; --i) {
        double w = y[i];
        // sum A[i][j] * x[j] for j > i
        for (int j = i + 1; j < n; ++j) {
            w -= A[i][j] * x[j];
        }
        x[i] = w / A[i][i];
    }
