    std::vector<double> pbuf(NN, 0.0);
    std::vector<double> qbuf(NN, 0.0);

    for (int t = 1; t <= tsteps; ++t) {
        /* First sweep – update column‑wise (v based on u). */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            /* Boundary rows */
            v[0][i] = 1.0;
            pbuf[idx(0,i)] = 0.0;
            qbuf[idx(0,i)] = v[0][i];

            /* Forward elimination (j = 1 .. n-2) */
            for (int j = 1; j < n - 1; ++j) {
                const double denom = a * pbuf[idx(j-1,i)] + b;
                pbuf[idx(j,i)] = -c / denom;
                const double num = -d * u[j][i - 1]
                                 + (1.0 + 2.0 * d) * u[j][i]
                                 - f * u[j][i + 1]
                                 - a * qbuf[idx(j-1,i)];
                qbuf[idx(j,i)] = num / denom;
            }

            v[n-1][i] = 1.0;

            /* Back substitution (j = n-2 .. 1) */
            for (int j = n - 2; j >= 1; --j) {
                v[j][i] = pbuf[idx(j,i)] * v[j + 1][i] + qbuf[idx(j,i)];
            }
        }

        /* Second sweep – update row‑wise (u based on v). */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            /* Boundary columns */
            u[i][0] = 1.0;
            pbuf[idx(i,0)] = 0.0;
            qbuf[idx(i,0)] = u[i][0];

            /* Forward elimination (j = 1 .. n-2) */
            for (int j = 1; j < n - 1; ++j) {
                const double denom = d * pbuf[idx(i,j-1)] + e;
                pbuf[idx(i,j)] = -f / denom;
                const double num = -a * v[i-1][j]
                                 + (1.0 + 2.0 * a) * v[i][j]
                                 - c * v[i + 1][j]
                                 - d * qbuf[idx(i,j-1)];
                qbuf[idx(i,j)] = num / denom;
            }

            u[i][n-1] = 1.0;

            /* Back substitution (j = n-2 .. 1) */
            for (int j = n - 2; j >= 1; --j) {
                u[i][j] = pbuf[idx(i,j)] * u[i][j + 1] + qbuf[idx(i,j)];
            }
        }
    }
