#include <cmath>
#include <vector>
#include <omp.h>

/* Optimised Deriche kernel – same signature, identical semantics. */
void kernel_deriche(int w, int h, double alpha,
                    std::vector<std::vector<float>>& imgIn,
                    std::vector<std::vector<float>>& imgOut,
                    std::vector<std::vector<float>>& y1,
                    std::vector<std::vector<float>>& y2)
{
    /* Pre‑computation of constants – algebraic constants are
       evaluated once; the trigamma terms stay unchanged.          */
    const float   eα  = std::exp(-alpha);
    const float   e2α = std::exp(-2.0f * alpha);
    const float   k   = 1.0f
                       - eα * (1.0f - eα)
                       / (1.0f + 2.0f * (float)alpha * eα - e2α);

    const float a1 = k,              a5 = k;
    const float a2 = k * eα * ((float)alpha - 1.0f),   a6 = a2;
    const float a3 = k * eα * ((float)alpha + 1.0f),   a7 = a3;
    const float a4 = -k * e2α,        a8 = a4;

    const float b1 = std::pow(2.0f, -(float)alpha);
    const float b2 = -e2α;

    /* Local flat buffers for speed – the outer two dimensions
       are still independent; we only collapse the inner loop
       for better cache‑reuse.                               */
    const int N = w * h;                   // total number of pixels
    std::vector<float> flatIn(N), flatOut(N);
    std::vector<float> flatY1(N), flatY2(N);

    /* Flatten input image once; keep same order (row‑major).*/
    #pragma omp parallel for collapse(2)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            flatIn[i*h + j] = imgIn[i][j];

    /* ---------- 1st pass : forward 1‑D filter (rows) ---------- */
    #pragma omp parallel for
    for (int i = 0; i < w; ++i) {
        const int base = i*h;
        float ym1 = 0.0f, ym2 = 0.0f, xm1 = 0.0f;
        for (int j = 0; j < h; ++j) {
            const float x = flatIn[base + j];
            const float y = a1*x + a2*xm1 + b1*ym1 + b2*ym2;
            flatY1[base + j] = y;
            xm1 = x;  ym2 = ym1;  ym1 = y;
        }
    }

    /// ---------- 2nd pass : backward 1‑D filter (rows) ----------
    #pragma omp parallel for
    for (int i = 0; i < w; ++i) {
        const int base = i*h;
        float yp1 = 0.0f, yp2 = 0.0f, xp1 = 0.0f, xp2 = 0.0f;
        for (int j = h-1; j >= 0; --j) {
            const float x = flatIn[base + j];
            const float y = a3*xp1 + a4*xp2 + b1*yp1 + b2*yp2;
            flatY2[base + j] = y;
            xp2 = xp1;  xp1 = x;
            yp2 = yp1;  yp1 = y;
        }
    }

    /* Combine first two stages (no scaling needed, c1=c2=1).    */
    #pragma omp parallel for collapse(2)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            flatOut[i*h + j] = flatY1[i*h + j] + flatY2[i*h + j];

    /* ---------- 3rd pass : forward 1‑D filter (columns) --------- */
    #pragma omp parallel for
    for (int j = 0; j < h; ++j) {
        float tm1 = 0.0f, ym1 = 0.0f, ym2 = 0.0f;
        for (int i = 0; i < w; ++i) {
            const int idx = i*h + j;
            const float x = flatOut[idx];
            const float y = a5*x + a6*tm1 + b1*ym1 + b2*ym2;
            flatY1[idx] = y;
            tm1 = x;  ym2 = ym1;  ym1 = y;
        }
    }

    /* ---------- 4th pass : backward 1‑D filter (columns) -------- */
    #pragma omp parallel for
    for (int j = 0; j < h; ++j) {
        float tp1 = 0.0f, tp2 = 0.0f, yp1 = 0.0f, yp2 = 0.0f;
        for (int i = w-1; i >= 0; --i) {
            const int idx = i*h + j;
            const float x = flatOut[idx];
            const float y = a7*tp1 + a8*tp2 + b1*yp1 + b2*yp2;
            flatY2[idx] = y;
            tp2 = tp1;  tp1 = x;
            yp2 = yp1;  yp1 = y;
        }
    }

    /* Final combination – identical to previous sum, c2=1.      */
    #pragma omp parallel for collapse(2)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            flatOut[i*h + j] = flatY1[i*h + j] + flatY2[i*h + j];

    /* Write back to the 2‑D output vector. */
    #pragma omp parallel for collapse(2)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            imgOut[i][j] = flatOut[i*h + j];
}
